import z from 'zod';

import { REQUEST_PARAMS, REQUEST_FETCH_PARAMS } from '@/shared/descriptions';
import { PaymentProtocol } from '@/shared/protocols/types';
import { Network } from '@agentcash/networks';
import { zodUrl } from '@/shared/url';

import { RequestMethod } from '../types';

export const requestMethodValues: readonly RequestMethod[] =
  Object.values(RequestMethod);

const methodSchema = z
  .enum(RequestMethod)
  .optional()
  .default(RequestMethod.GET)
  .describe(REQUEST_PARAMS.method);

export const coreRequestSchema = z.object({
  url: zodUrl.describe(REQUEST_PARAMS.url),
  method: methodSchema,
});

export const paymentNetworks: Network[] = [
  Network.BASE,
  Network.SOLANA,
  Network.TEMPO,
];

export const paymentProtocols: PaymentProtocol[] = [
  PaymentProtocol.X402,
  PaymentProtocol.MPP,
];

export const fetchShape = {
  paymentNetwork: z
    .enum(paymentNetworks)
    .optional()
    .describe(REQUEST_FETCH_PARAMS.paymentNetwork),
  paymentProtocol: z
    .enum(paymentProtocols)
    .optional()
    .describe(REQUEST_FETCH_PARAMS.paymentProtocol),
  maxAmount: z
    .number()
    .positive()
    .optional()
    .describe(REQUEST_FETCH_PARAMS.maxAmount),
  timeout: z
    .number()
    .int()
    .positive()
    .optional()
    .describe(REQUEST_PARAMS.timeout),
};
